use std::os::raw::c_uint;

// Simulates the Mesa libspirv_to_dxil C entry point.
// Precondition (unenforced): words must point to >= 5 u32 values.
unsafe fn spirv_to_dxil_inner(words: *const c_uint, _word_count: usize) -> bool {
    // Reads words[0] unconditionally to check the SPIR-V magic number.
    // If the slice is empty this is an out-of-bounds read — UB.
    let magic = *words;
    magic == 0x07230203
}

/// Logical precondition: `spirv_words` must be a valid SPIR-V binary
/// containing at least 5 words (the mandatory SPIR-V header).
/// Passing a shorter slice violates this precondition and causes the
/// inner parser to read past the end of the allocation.
pub fn dump_nir(spirv_words: &[u32]) -> bool {
    // No length guard before handing the raw pointer into C.
    unsafe {
        spirv_to_dxil_inner(
            spirv_words.as_ptr() as *const c_uint,
            spirv_words.len(),
        )
    }
}

