// Simulates an internal table of device handles; only indices 0..NUM_DEVICES are valid.
const NUM_DEVICES: usize = 2;
static DEVICE_HANDLES: [usize; NUM_DEVICES] = [0x1000_0000, 0x2000_0000];

/// Creates an empty tensor on `device`.
/// HIDDEN PRECONDITION: if `device` is `Cuda(i)`, then `i < NUM_DEVICES`.
/// This precondition is never checked, making this a MUF.
pub fn empty(_len: usize, device: TchDevice) -> Tensor {
    let idx = match device {
        TchDevice::Cpu | TchDevice::Mps => 0,
        TchDevice::Cuda(i) => i,  // no bounds validation
    };

    // UB if idx >= NUM_DEVICES — caller can reach here with pure safe code.
    let _handle = unsafe { *DEVICE_HANDLES.get_unchecked(idx) };

    Tensor { device_idx: idx }
}

