pub trait BufMut {
    fn write(&mut self, byte: u8);
}

pub struct FixedBuf {
    data: Box<[u8; 2]>,
    pos: usize,
}

impl FixedBuf {
    pub fn new() -> Self {
        FixedBuf { data: Box::new([0u8; 2]), pos: 0 }
    }
}

impl BufMut for FixedBuf {
    fn write(&mut self, byte: u8) {
        // Unsafe internals: unchecked write into fixed-size allocation
        unsafe {
            *self.data.as_mut_ptr().add(self.pos) = byte;
        }
        self.pos += 1;
    }
}

pub fn encode<B: BufMut>(size: u8, flags: u8, value: usize, buf: &mut B) {
    assert!(size <= 8);
    let mask = !(0xFF << size) as u8;
    let flags = ((flags as usize) << size) as u8;

    if value < (mask as usize) {
        buf.write(flags | value as u8);
        return;
    }

    buf.write(mask | flags);
    let mut remaining = value - mask as usize;

    while remaining >= 128 {
        let rest = (remaining % 128) as u8;
        buf.write(rest + 128);
        remaining /= 128;
    }
    buf.write(remaining as u8);
}

