impl Scanner {
    pub fn new(data: Vec<u8>) -> Self {
        let len = data.len();
        Scanner { data, pos: 0, len }
    }

    /// Safe API — but breaks the invariant len <= data.len()
    pub fn set_reported_len(&mut self, len: usize) {
        self.len = len;
    }

