        self.pos += 1;
    }

    fn at_end(&self) -> bool {
        self.pos >= self.len
    }

    fn curr_byte_unchecked(&self) -> u8 {
        unsafe { *self.data.get_unchecked(self.pos) }
    }

    pub fn curr_byte(&self) -> Option<u8> {
        if !self.at_end() {
            Some(self.curr_byte_unchecked())
        } else {
            None
        }
    }
}

