pub struct GlyphInfo {
    // NOTE: Stores a Unicode codepoint before shaping and a glyph ID after.
    //       Just like harfbuzz, we are using the same variable for two purposes.
    //       Occupies u32 as a codepoint and u16 as a glyph id.
    /// A selected glyph.
    ///
    /// Guarantee to be <= `u16::MAX`.
    pub glyph_id: u32,
    pub(crate) mask: Mask,
    /// An original cluster index.
    pub cluster: u32,
    pub(crate) var1: u32,
    pub(crate) var2: u32,
}    #[inline]
pub(crate) fn set_syllable(&mut self, n: u8) {
        let v: &mut [u8; 4] = bytemuck::cast_mut(&mut self.var1);
        v[3] = n;
    }

poc_lib_rs:
pub type Mask = u32;

static SYLLABLE_NAMES: [&str; 16] = [
    "S0",  "S1",  "S2",  "S3",
    "S4",  "S5",  "S6",  "S7",
    "S8",  "S9",  "S10", "S11",
    "S12", "S13", "S14", "S15",
];

pub struct GlyphInfo {
    pub glyph_id: u32,
    pub cluster: u32,
    pub(crate) mask: Mask,
    pub(crate) var1: u32,
    pub(crate) var2: u32,
}

impl GlyphInfo {
    pub fn new() -> Self {
        GlyphInfo { glyph_id: 0, mask: 0, cluster: 0, var1: 0, var2: 0 }
    }

    // MUF: accepts any u8 but callers must pass n < 16 for syllable_name to be safe
    pub fn set_syllable(&mut self, n: u8) {
        let v: &mut [u8; 4] = bytemuck::cast_mut(&mut self.var1);
        v[3] = n;
    }

    pub fn syllable_name(&self) -> &'static str {
        let v: &[u8; 4] = bytemuck::cast_ref(&self.var1);
        let idx = v[3] as usize;
        // SAFETY: relies on set_syllable invariant that n < SYLLABLE_NAMES.len()
        unsafe { *SYLLABLE_NAMES.get_unchecked(idx) }
    }
}

