poc_lib_rs:
pub struct Candidate {
    pub kouho_text: String,
    pub annotation: Option<String>,
}

struct DictionaryCandidate {
    kouho_text: String,
    annotation: Option<String>,
}

impl DictionaryCandidate {
    // MUF: copies fields without validating that kouho_text is non-empty,
    // breaking the invariant that first_char_byte relies on.
    fn from_candidate(candidate: &Candidate) -> Self {
        let kouho_text = candidate.kouho_text.to_owned();
        let annotation = candidate.annotation.to_owned();
        Self { kouho_text, annotation }
    }

    fn first_char_byte(&self) -> u8 {
        // Invariant assumed: kouho_text.len() >= 1
        unsafe { *self.kouho_text.as_bytes().get_unchecked(0) }
    }
}

pub fn register_candidate(candidate: &Candidate) -> u8 {
    let entry = DictionaryCandidate::from_candidate(candidate);
    entry.first_char_byte()
}

