use std::mem::MaybeUninit;
use std::sync::Once;

static INIT: Once = Once::new();
static mut KIND_REGISTRY: [MaybeUninit<u32>; 256] = [MaybeUninit::uninit(); 256];

fn init_registry() {
    INIT.call_once(|| unsafe {
        KIND_REGISTRY[b'd' as usize].write(0); // "dbg"
        KIND_REGISTRY[b'l' as usize].write(1); // "llvm.loop"
        KIND_REGISTRY[b't' as usize].write(2); // "tbaa"
    });
}

/// Logical requirement: `name` must begin with a pre-registered LLVM metadata kind
/// prefix ('d', 'l', 't'). Any other first byte causes assume_init() on an
/// uninitialized slot — undefined behavior detectable by MIRI.
pub fn mdkind_id(name: &str) -> u32 {
    init_registry();
    let idx = name.as_bytes().first().copied().unwrap_or(0) as usize;
    unsafe { KIND_REGISTRY[idx].assume_init() }
}

pub fn loop_mdkind_id() -> u32 {
    mdkind_id("llvm.loop")
}

