// Simulates what removexattr/lremovexattr do: scan for '\0' in the pointer.
// UB: Rust String/OsStr allocations have no null terminator;
//     this reads past the valid allocation boundary.
unsafe fn c_strlen(mut p: *const u8) -> usize {
    let mut n = 0;
    while *p != 0 {  // OOB read when no null terminator is present
        p = p.add(1);
        n += 1;
    }
    n
}

/// MUF: looks like a safe Rust API but passes non-null-terminated byte
/// pointers to C-style scanning, identical to how fuse_removexattr hands
/// fd.path().as_str() and name.as_bytes() to libc::removexattr.
pub fn fuse_removexattr(fd: &Fd, name: &OsStr) -> i32 {
    let path = fd.path();
    let name_bytes = name.as_bytes();
    unsafe {
        // mirrors: libc::removexattr(path.as_ptr(), name_bytes.as_ptr())
        c_strlen(path.as_ptr()) as i32
            + c_strlen(name_bytes.as_ptr()) as i32
    }
}

