/// Mirrors fuse_listxattr: passes fd.path() as a C-string to the mock FFI sink.
/// UB: Rust &str has no null terminator; scanning for '\0' reads past the allocation.
pub fn fuse_listxattr(fd: &Fd, buf: &mut [u8]) -> usize {
    let bytes = fd.path().as_bytes();
    let ptr = bytes.as_ptr();
    let mut len = 0usize;
    unsafe {
        // Simulates what C listxattr does: scan until '\0'.
        // When path has no null terminator this is an out-of-bounds read.
        while *ptr.add(len) != 0 {
            len += 1;
        }
    }
    let copy = len.min(buf.len()).min(bytes.len());
    buf[..copy].copy_from_slice(&bytes[..copy]);
    len
}

