#[repr(C)]
pub struct Padded {
    pub a: u8,
    // 3 bytes of uninitialized padding here (repr(C) guarantees layout)
    pub b: u32,
}

pub trait Gl {
    fn buffer_sub_data_untyped(&self, target: u32, offset: isize, size: isize, data: *const c_void);
