pub struct MockGl;

impl Gl for MockGl {
    fn buffer_sub_data_untyped(&self, _target: u32, _offset: isize, size: isize, data: *const c_void) {
        // Simulate what a GPU driver does: consume every byte it receives.
        // Reads uninitialized padding bytes — UB detectable by MIRI.
        let bytes = unsafe { std::slice::from_raw_parts(data as *const u8, size as usize) };
        let _checksum: u8 = bytes.iter().copied().fold(0u8, u8::wrapping_add);
    }
}

pub fn buffer_sub_data<T>(gl_: &dyn Gl, target: u32, offset: isize, data: &[T]) {
    gl_.buffer_sub_data_untyped(
        target,
        offset,
        (data.len() * size_of::<T>()) as isize,
        data.as_ptr() as *const c_void,
    );
}

