pub struct Context {
    candidates: Vec<String>,
    current_index: usize,
}

impl Context {
    pub fn new(candidates: Vec<String>) -> Self {
        Context { candidates, current_index: 0 }
    }

    // MUF: stores index validated against current len, but len can change later
    pub fn select_candidate_at(&mut self, i: i32) -> bool {
        let len = self.candidates.len();
        if len == 0 {
            return false;
        }
        if i < 0 {
            self.current_index = 0;
        } else if i >= len as i32 {
            self.current_index = len - 1;
        } else {
            self.current_index = i as usize;
        }
        true
    }

    pub fn retain_candidates(&mut self, keep: usize) {
        self.candidates.truncate(keep);
        // current_index is NOT updated: stale index survives
    }

    pub fn get_selected(&self) -> &str {
        // UB: out-of-bounds read when current_index >= candidates.len()
        unsafe { self.candidates.get_unchecked(self.current_index) }
    }
}

