        "gamma".to_string(),
        "delta".to_string(),
        "epsilon".to_string(),
    ]);

    // Safe: index 4 is valid for a 5-element list
    ctx.select_candidate_at(4);

    // Safe: shrink the list — now only 2 elements remain
    ctx.retain_candidates(2);

    // UB: current_index is 4, but candidates.len() is 2
    // get_unchecked reads out of bounds — detectable by miri
    println!("{}", ctx.get_selected());
}

