pub struct FuseBuf {
    data: Vec<u8>,
    // raw pointer into data's heap block — becomes dangling after reallocation
    view: *const u8,
}

impl FuseBuf {
    pub fn new(n: usize) -> Self {
        let data = vec![0u8; n];
        let view = data.as_ptr();
        FuseBuf { data, view }
    }

    // Mirrors buf.reserve(1) in fuse_readlinkat: resizing past current
    // capacity triggers reallocation, freeing the block that `view` points into.
    pub fn grow(&mut self) {
        let cap = self.data.capacity();
        self.data.resize(cap + 1, 0);
    }

    pub fn read_first(&self) -> u8 {
        unsafe { *self.view } // UB: dangling pointer if grow() reallocated
    }
}

