    pub fn insert(&self, k: K, v: V) {
        let items = unsafe { &mut *self.items.get() };
        match items.iter().position(|(key, _)| key == &k) {
            None => items.push((k, v)),
            Some(x) => items[x].1 = v,
        }
    }
