pub struct FakeMap<V> {
    items: Vec<V>,
    cache: HashMap<String, usize>,
}

impl<V> FakeMap<V> {
    pub fn new() -> Self {
        FakeMap { items: Vec::new(), cache: HashMap::new() }
    }

    pub fn insert(&mut self, key: impl Into<String>, value: V) {
        let idx = self.items.len();
        self.cache.insert(key.into(), idx);
        self.items.push(value);
