use std::borrow::Borrow;

pub struct FakeMap<K, V> {
    items: Vec<(K, V)>,
    len: usize,
}

impl<K, V> FakeMap<K, V> {
    pub fn new() -> Self {
        Self { items: Vec::new(), len: 0 }
    }

    pub fn insert(&mut self, k: K, v: V) {
        self.items.push((k, v));
        self.len += 1;
    }

    fn get_idx_of_key<Q: ?Sized>(&self, key: &Q) -> Option<usize>
    where
        Q: PartialEq,
        K: Borrow<Q>,
    {
        self.items.iter().position(|(k, _)| k.borrow() == key)
    }

    // MUF: shrinks `items` but never decrements `len` — stale length
    pub fn remove<Q: ?Sized>(&mut self, key: &Q) -> Option<V>
    where
        Q: PartialEq,
        K: Borrow<Q>,
    {
        self.get_idx_of_key(key).map(|idx| self.items.remove(idx).1)
    }

    // Trusts `self.len` for unchecked indexing — UB if len is stale
    pub fn last_value(&self) -> Option<&V> {
        if self.len == 0 {
            return None;
        }
        Some(unsafe { &self.items.get_unchecked(self.len - 1).1 })
    }
}

