use std::collections::HashMap;

static mut TIMERS: Option<HashMap<u64, bool>> = None;

pub fn init_timers() {
    unsafe { TIMERS = Some(HashMap::new()); }
}

pub fn add_timer(id: u64) {
    unsafe { TIMERS.as_mut().unwrap().insert(id, false); }
}

// Safe signature hides interior unsafe: mutates shared state with no lock.
pub fn _clear_timer(id: u64) {
    unsafe {
        let map = TIMERS.as_mut().unwrap();
        if map.contains_key(&id) {
            map.remove(&id);
        }
    }
}

