    }
    // Barrier forces all threads to race at exactly the same moment.
    let barrier = Arc::new(Barrier::new(10));
    let handles: Vec<_> = (0..10u64)
        .map(|i| {
            let b = Arc::clone(&barrier);
            thread::spawn(move || {
                b.wait();
                _clear_timer(i);      // concurrent mutation — data race
                _clear_timer(i + 10); // same HashMap internal state
            })
        })
        .collect();
    for h in handles {
        h.join().unwrap();
    }
}

