use std::cell::Cell;

pub struct UintConstructor {
    pub data: Cell<Vec<u64>>,
}

// UNSOUND: Cell<T> is !Sync; this unsafe impl lies to the compiler,
// allowing the type to be shared across threads without synchronization.
unsafe impl Sync for UintConstructor {}

pub fn new() -> UintConstructor {
    UintConstructor {
        data: Cell::new(Vec::new()),
    }
}

// Safe public API — callers never need to write `unsafe`.
pub fn push(state: &UintConstructor, val: u64) {
    let mut v = state.data.take(); // non-atomic: reads then zeroes the Cell
    v.push(val);
    state.data.set(v);             // non-atomic: writes back
    // A concurrent thread can interleave between take() and set(),
    // causing one thread's push to be silently lost, or corrupting
    // the Vec's internal length/capacity pointers -> data race UB.
}

pub fn len(state: &UintConstructor) -> usize {
    let v = state.data.take();
    let n = v.len();
    state.data.set(v);
    n
}

