use std::sync::atomic::{AtomicUsize, Ordering};

pub struct CountedIndex {
    val: AtomicUsize,
    mask: usize,
}

impl CountedIndex {
    pub fn new(cap: usize) -> Self {
        assert!(cap.is_power_of_two());
        CountedIndex { val: AtomicUsize::new(0), mask: cap - 1 }
    }

    pub fn increment(&self) {
        self.val.fetch_add(1, Ordering::Relaxed);
    }

    #[inline(always)]
    pub fn load_raw(&self, ord: Ordering) -> usize {
        self.val.load(ord)
    }
}

pub struct RingBuf {
    pub idx: CountedIndex,
    data: Vec<u8>,
}

impl RingBuf {
    pub fn new(cap: usize) -> Self {
        RingBuf {
            idx: CountedIndex::new(cap),
            data: vec![0u8; cap],
        }
    }

    // Precondition: idx.val < data.len() — violated when load_raw() is used without masking
    pub fn peek(&self) -> u8 {
        unsafe { *self.data.get_unchecked(self.idx.load_raw(Ordering::Relaxed)) }
    }
}

