use std::cell::{Cell, RefCell};

pub struct List<T> {
    nodes: RefCell<Vec<Box<T>>>,
    // raw pointer to the last element's heap allocation
    tail_ptr: Cell<*const T>,
}

impl<T> List<T> {
    pub fn new() -> Self {
        List {
            nodes: RefCell::new(Vec::new()),
            tail_ptr: Cell::new(std::ptr::null()),
        }
    }

    pub fn push_back(&self, elem: T) {
        let boxed = Box::new(elem);
        let ptr: *const T = &*boxed;
        self.nodes.borrow_mut().push(boxed);
        self.tail_ptr.set(ptr);
    }

    // BUG: drops the Box<T> but never clears tail_ptr, leaving it dangling
    pub fn pop_back(&self) -> Option<T> {
        self.nodes.borrow_mut().pop().map(|b| *b)
    }

    // Unsound: the returned reference may outlive the Box it points into
    pub fn peek_back(&self) -> Option<&T> {
        let ptr = self.tail_ptr.get();
        if ptr.is_null() {
            None
        } else {
            unsafe { Some(&*ptr) }
        }
    }
}

