pub type Inst = u32;

#[derive(Clone, Copy)]
pub struct WReg(pub u8);

#[derive(Clone, Copy)]
pub struct Reg(pub WReg);

fn mmath(funct3: u32, rd: Reg, rs1: Reg, imm: u16) -> Inst {
    // Does not mask register indices to 5 bits; values > 31 corrupt adjacent bit fields.
    ((imm as u32 & 0xFFF) << 20)
        | ((rs1.0.0 as u32) << 15)
        | (funct3 << 12)
        | ((rd.0.0 as u32) << 7)
        | 0b001_0011
}

pub fn addi(rd: Reg, rs1: Reg, imm: u16) -> Inst {
    mmath(0, rd, rs1, imm)
}

/// Execute a single ADDI instruction against a simulated register file.
/// CONTRACT: all register fields must be valid 5-bit indices (0-31).
pub fn execute(inst: Inst, regs: &mut [u32; 32]) {
    let rd  = ((inst >>  7) & 0x1F) as usize;
    let rs1 = (inst >> 15) as usize; // trusts 5-bit encoding; no bounds re-check
    let imm = (inst as i32) >> 20;
    unsafe {
        let val = *regs.get_unchecked(rs1); // UB: rs1 may be > 31
        *regs.get_unchecked_mut(rd) = val.wrapping_add(imm as u32);
    }
}

