    // WReg(255) overflows the 5-bit rs1 field; execute() decodes rs1=255
    // and calls get_unchecked(255) on a 32-element array — out-of-bounds UB.
    let inst = addi(Reg(WReg(0)), Reg(WReg(255)), 0);
    execute(inst, &mut regs);
}

