poc_lib_rs:
use std::arch::x86_64::*;

pub struct AvxState {
    state: (u32, u32),
}

impl AvxState {
    /// MUF: gates construction on runtime AVX2 detection;
    /// methods on Self call AVX2 intrinsics trusting this invariant.
    pub fn new(initial: u32) -> Option<Self> {
        if is_x86_feature_detected!("avx2") {
            Some(Self { state: (initial & 0xffff, initial >> 16) })
        } else {
            None
        }
    }

    /// Safe public wrapper — assumes AVX2 was verified by new().
    pub fn step(&self) -> u32 {
        // SAFETY: relies on AVX2 invariant from new() — violated by Default
        unsafe { self.avx2_step() }
    }

    #[target_feature(enable = "avx2")]
    unsafe fn avx2_step(&self) -> u32 {
        let a = _mm256_set1_epi32(self.state.0 as i32);
        let b = _mm256_set1_epi32(self.state.1 as i32);
        _mm256_extract_epi32(_mm256_add_epi32(a, b), 0) as u32
    }
}

/// BUG: constructs AvxState without any AVX2 check,
/// invalidating the invariant that step() depends on.
impl Default for AvxState {
    fn default() -> Self {
        AvxState { state: (1, 2) }
    }
}

