use muf_poc::AvxState;

fn main() {
    // Entirely safe code: Default bypasses is_x86_feature_detected!,
    // then step() calls AVX2 intrinsics unconditionally.
    // On non-AVX2 x86_64 hardware this is SIGILL; MIRI flags it as
    // an unsupported intrinsic (hardware-feature UB).
    let s = AvxState::default();
    println!("{}", s.step());
}

